/**
 * User notification preferences model.
 *
 * Controls how and when users receive notifications.
 * Currently supports email as the only channel — designed
 * to be extensible when additional channels are added.
 */

import type { NotificationType } from './notification.js';

/**
 * Notification categories that group related notification types.
 * Users subscribe/unsubscribe at the category level.
 */
export type NotificationCategory = 'orders' | 'account' | 'system';

/**
 * How frequently email notifications are delivered.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary (not yet implemented)
 * - 'weekly-digest': batch into a weekly summary (not yet implemented)
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master switch for all email notifications */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Per-category opt-in/out */
  categories: Record<NotificationCategory, boolean>;
}

/**
 * Full user preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categories?: Partial<Record<NotificationCategory, boolean>>;
}

/**
 * Map a NotificationType to its category for preference lookup.
 */
const NOTIFICATION_TYPE_CATEGORY: Record<NotificationType, NotificationCategory> = {
  'order-confirmation': 'orders',
  'order-status-update': 'orders',
  'user-welcome': 'account',
  'user-updated': 'account',
  'system-alert': 'system',
};

export function getCategoryForType(type: NotificationType): NotificationCategory {
  return NOTIFICATION_TYPE_CATEGORY[type];
}

/**
 * Create default preferences for a new user.
 * All notifications enabled by default.
 */
export function createDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: {
      orders: true,
      account: true,
      system: true,
    },
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with user-preferences-specific queries.
 * Stores email preferences as a JSON string in the database.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class UserPreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailPreferences,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages user notification settings and provides a query interface
 * for the NotificationService to check before sending.
 *
 * Depends on:
 * - UserPreferencesRepository (data layer) for persistence
 */

import type { UserPreferences, UpdateEmailPreferencesInput } from '../models/user-preferences.js';
import { createDefaultEmailPreferences, getCategoryForType } from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type { UserPreferencesRepository } from '../repositories/user-preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter — for testing only. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: UserPreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user: ${userId}`);
    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId,
      email: createDefaultEmailPreferences(),
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    return prefs;
  }

  /**
   * Update a user's email notification preferences.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating email preferences for user: ${userId}`);

    const prefs = this.getOrCreatePreferences(userId);
    const updatedEmail = { ...prefs.email };

    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.categories) {
      updatedEmail.categories = {
        ...updatedEmail.categories,
        ...input.categories,
      };
    }

    return this.preferencesRepository.update(prefs.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification should be sent to a user.
   *
   * Returns true if the user has not opted out of the given
   * notification type on the given channel. If no preferences
   * exist for the user, defaults to allowing the notification.
   */
  shouldNotify(
    userId: string,
    notificationType: NotificationType,
    channel: NotificationChannel,
  ): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences saved → allow all notifications (default opt-in)
    if (!prefs) {
      return true;
    }

    if (channel === 'email') {
      if (!prefs.email.enabled) {
        return false;
      }
      if (prefs.email.frequency === 'none') {
        return false;
      }
      const category = getCategoryForType(notificationType);
      return prefs.email.categories[category];
    }

    // Unknown channel — allow by default
    return true;
  }

  /**
   * Delete preferences for a user.
   */
  deletePreferences(userId: string): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);
    if (!prefs) {
      return false;
    }
    return this.preferencesRepository.delete(prefs.id);
  }
}

