  // Check user preferences before sending
  if (input.userId && this.preferencesService) {
    if (!this.preferencesService.shouldNotify(input.userId, input.type, input.channel)) {
      this.logger.info(
        `Notification suppressed for user ${input.userId}: ${input.type} via ${input.channel} (user preference)`,
