+ * All notifications enabled by default.
+ */
+export function createDefaultEmailPreferences(): EmailPreferences {
+  return {
+    enabled: true,
+    frequency: 'immediate',
+    categories: {
+      orders: true,
+      account: true,
+      system: true,
+    },
+  };
+}

